select count(*) from postgres.comments as c, postgres.posts as p, postgres.postlinks as pl, postgres.posthistory as ph, postgres.votes as v, postgres.badges as b, postgres.users as u where p.id = pl.relatedpostid and b.userid = u.id and c.userid = u.id and p.id = v.postid and p.id = c.postid and p.id = ph.postid and p.score<=40 and p.commentcount>=0 and p.creationdate>=timestamp '2010-07-28 17:40:56' and p.creationdate<=timestamp '2014-09-11 04:22:44' and pl.linktypeid=1;
